import{_ as t,o as a,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"3. Allowances And Top Of Band Payments","description":"","frontmatter":{"title":"3. Allowances And Top Of Band Payments","eba":"Biomedical Engineers 2025-2028","topics":["appendices","allowances","remuneration","rates","pay-rates","top-of-band","cash-payments","professional-development","salary-circular","circular 872"]},"headers":[],"relativePath":"ebas/biomedical-engineers/appendices/3-allowances-and-top-of-band-payments.md","filePath":"ebas/biomedical-engineers/appendices/3-allowances-and-top-of-band-payments.md"}'),n={name:"ebas/biomedical-engineers/appendices/3-allowances-and-top-of-band-payments.md"};function l(i,e,r,c,d,p){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_3-allowances-and-top-of-band-payments" tabindex="-1">3. Allowances And Top Of Band Payments <a class="header-anchor" href="#_3-allowances-and-top-of-band-payments" aria-label="Permalink to &quot;3. Allowances And Top Of Band Payments&quot;">​</a></h1><p>Related pay information</p><ul><li><a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Wage Rates</a></li><li><a href="/eba/ebas/biomedical-engineers/wages/26-wages-and-allowances.html">Wages and Allowances (Clause 26)</a></li><li><a href="/eba/ebas/biomedical-engineers/wages/27-top-of-band-payment.html">Top of Band Payment (Clause 27)</a></li></ul><p>Source: Salary Circular 872 (1 August 2025)</p><p>The payment tables below are sourced from Salary Circular 872. Part-time and casual employees receive amounts on a pro-rata basis where indicated. See the referenced clauses for full eligibility criteria.</p><table class="pay-table"><caption>Cash Payments (Subclause 26.4)</caption><thead><tr><th class="pt-class">Payment</th><th class="pt-class">Timing</th><th class="pt-rate">Amount</th></tr></thead><tbody><tr><td class="pt-class">Patience in Bargaining</td><td class="pt-class">No later than FFPPOOA the Agreement has been in effect for 30 days</td><td class="pt-rate">$2,500.00</td></tr><tr><td class="pt-class">Once-off cash incentive payment</td><td class="pt-class">No later than FFPPOOA the Agreement has been in effect for 30 days</td><td class="pt-rate">$5,180.00</td></tr></tbody></table><table class="pay-table"><caption>Top of Band Payment (Clause 27)</caption><thead><tr><th class="pt-class">Anniversary Date</th><th class="pt-rate">Amount</th><th class="pt-class">Eligible Classification</th><th class="pt-code">Pay Code</th></tr></thead><tbody><tr><td class="pt-class">FFPPOOA 1 August 2024</td><td class="pt-rate">$2,060.00</td><td class="pt-class">Class 2 Pay Point 2</td><td class="pt-code">PH56</td></tr><tr><td class="pt-class">FFPPOOA 1 August 2025</td><td class="pt-rate">$2,121.80</td><td class="pt-class">Class 3 Pay Point 3</td><td class="pt-code">HP2</td></tr><tr><td class="pt-class">FFPPOOA 1 August 2026</td><td class="pt-rate">$2,185.45</td><td class="pt-class">Class 4 Pay Point 3</td><td class="pt-code">PI5</td></tr><tr><td class="pt-class">FFPPOOA 1 August 2027 and each 1 August thereafter</td><td class="pt-rate">$2,251.02</td><td class="pt-class">Class 5 Pay Point 3*</td><td class="pt-code">PI8</td></tr></tbody></table><p>*From FFPPOOA commencement of the Agreement</p><table class="pay-table"><caption>Professional Development Allowance (Subclause 71.4)</caption><thead><tr><th class="pt-class">Period</th><th class="pt-rate">Amount</th></tr></thead><tbody><tr><td class="pt-class">FFPPOOA commencement of the Agreement</td><td class="pt-rate">$500.00</td></tr><tr><td class="pt-class">FFPPOOA commencement of the Agreement</td><td class="pt-rate">$1,500.00</td></tr><tr><td class="pt-class">FFPPOOA 1 August 2025</td><td class="pt-rate">$1,545.00</td></tr><tr><td class="pt-class">FFPPOOA 1 August 2026</td><td class="pt-rate">$1,591.35</td></tr><tr><td class="pt-class">FFPPOOA 1 August 2027 and each 1 August thereafter</td><td class="pt-rate">$1,639.09</td></tr></tbody></table><p>Process for conversion where fixed term employment in the same or a substantially similar position exceeds the maximum duration of 3 years:</p><p><strong>(a)</strong> In accordance with this Appendix 3, an Employer must, assuming they wish to retain the Employee, make an offer of ongoing employment to a currently employed fixed term Employee if the Employee has been employed on fixed term contract(s) involving the same or substantially similar work pursuant to subclause 22.3(c).</p><p><strong>(b)</strong> The offer must be:</p><ul><li>(i) given to the Employee within the period of 21 days before their fixed term employment has reached 3 years&#39; duration,</li><li>(ii) made in writing;</li><li>(iii) an offer to convert to ongoing employment at the same classification or equivalent as the Employee&#39;s fixed term role; and</li><li>(iv) consistent with the employee&#39;s existing number of ordinary hours.</li></ul><p><strong>(c)</strong> Notwithstanding subclause (b) above, the Employer is not required to make an offer under that subclause to an Employee if there are:</p><ul><li>(i) reasonable business grounds not to do so (see subclause (e) below), or</li><li>(ii) exceptional or unforeseen circumstances.</li></ul><p><strong>(d)</strong> If subclause (c) above applies, the Employer must give written notice to the Employee. The notice must:</p><ul><li>(i) advise the Employee that the Employer is not making an offer of ongoing employment;</li><li>(ii) provide details of the reasons for not making the offer, including the reasonable business grounds and details of any exceptional or unforeseen circumstances; and</li><li>(iii) be given to the Employee within the period of 21 days before their fixed term employment has reached 3 years&#39; duration.</li></ul><p><strong>(e)</strong> For the purposes of subclause (c)(i) above, and without limitation, reasonable business grounds include:</p><ul><li>(i) there is no ongoing vacancy available in which to place the Employee, and/or</li><li>(ii) the Employee&#39;s position will cease to exist in the coming 12 months.</li></ul><p><strong>(f)</strong> If an Employer fails to make an offer of ongoing employment to an eligible fixed term Employee, the Employee may request in writing conversion to ongoing employment. Approval to convert to ongoing employment will not be withheld unless one of the exceptions in subclause (c) above applies.</p>',20)])])}const u=t(n,[["render",l]]);export{h as __pageData,u as default};
